PRAGMA journal_mode=WAL;
PRAGMA foreign_keys=ON;

CREATE TABLE IF NOT EXISTS direcciones (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  depto       TEXT    NOT NULL,
  municipio   TEXT    NOT NULL,
  cod_postal  INTEGER NOT NULL,
  barrio      TEXT    NOT NULL,
  cod_mun     INTEGER,
  cod_barrio  INTEGER
);

CREATE INDEX IF NOT EXISTS idx_depto     ON direcciones(depto);
CREATE INDEX IF NOT EXISTS idx_municipio ON direcciones(municipio);
CREATE INDEX IF NOT EXISTS idx_postal    ON direcciones(cod_postal);

BEGIN TRANSACTION;
COMMIT;